const speakersDataEl=document.getElementById("speakers-data"),speakerItems=document.querySelectorAll(".event-speakers .cell"),speakerModal=document.getElementById("speaker-modal"),speakerContent=document.getElementById("speaker-content");if(speakersDataEl){const mapData=JSON.parse(speakersDataEl.textContent),{speakers:speakers}=mapData;speakerItems.forEach((speakerItem=>{speakerItem.addEventListener("click",(()=>{const speaker=speakers.find((item=>item.id===speakerItem.dataset.id));if(!speaker)return;speakerModal.heading=`${speaker.first_name} ${speaker.last_name}`,speakerContent.innerHTML=speaker.content;const oldSubHeading=document.querySelector("#speaker-modal .sub-heading");oldSubHeading&&oldSubHeading.remove();const subHeadingHtml=`\n                    <div class="sub-heading">\n                    <div class="spacer x-small"></div>\n                    <p id="speaker-job-title">${speaker.company_name?`${speaker.job_title} at ${speaker.company_name}`:speaker.job_title}</p>\n                    <div class="spacer small"></div>\n                    <div class="event-card-wrap">\n                         <div class="grid-x">\n                         <i class="icon-email-1"></i>\n                         <span id="speaker-email">${speaker.contact.email}</span>\n                         </div>\n                    </div>\n                    <div class="spacer"></div>\n                    <hr>\n                    </div>\n                    `;document.querySelector("#speaker-modal .icon-close-1").insertAdjacentHTML("afterend",subHeadingHtml),speakerModal.open()}))}))}